const allowedTools = new Set(["search", "calculator", "resume_reader"]);

function allowToolRequest(request) {
  if (!allowedTools.has(request.tool)) return false;
  const text = request.text.toLowerCase();
  if (text.includes("secret") || text.includes("token") || text.includes("ignore previous")) return false;
  return true;
}
